   100→export function createAccessToken({
   101→	userId,
   102→	sessionId,
   103→	role,
   104→	companyId,
   105→}: {
   106→	userId: string;
   107→	sessionId: string;
   108→	role: 'admin' | 'member' | null;
   109→	companyId: string | null;
   110→}): string {
   111→	return jwt.sign(
   112→		{ user_id: userId, session_id: sessionId, role, company_id: companyId },
   113→		JWT_SECRET,
   114→		{ expiresIn: 3600 },
   115→	);
   116→}
   117→
   118→export async function createSession({
   119→	redis,
   120→	userId,
   121→	sessionId,
   122→	role,
   123→	companyId,
   124→}: {
   125→	redis: Redis;
   126→	userId: string;
   127→	sessionId: string;
   128→	role: 'admin' | 'member' | null;
   129→	companyId: string | null;
   130→}): Promise<string> {
   131→	const refreshToken = randomUUID();
   132→	const now = new Date().toISOString();
   133→
   134→	const session: ISession = {
   135→		user_id: userId,
   136→		session_id: sessionId,
   137→		role,
   138→		company_id: companyId,
   139→		provider: 'github',
   140→		ip: '127.0.0.1',
   141→		user_agent: 'test-agent',
   142→		created_at: now,
   143→		last_active: now,
   144→	};
   145→
   146→	const payload = { user_id: userId, session_id: sessionId };
   147→
   148→	await redis
   149→		.multi()
   150→		.set(`session:${userId}:${sessionId}`, JSON.stringify(session), 'EX', SESSION_TTL)
   151→		.sadd(`sessions:${userId}`, sessionId)
   152→		.set(`refresh:${refreshToken}`, JSON.stringify(payload), 'EX', SESSION_TTL)
   153→		.exec();
   154→
   155→	return refreshToken;
   156→}
