   183→	const accessToken = createAccessToken({
   184→		userId: user._id,
   185→		sessionId,
   186→		role,
   187→		companyId,
   188→	});
   189→
   190→	return {
   191→		user,
   192→		accessToken,
   193→		session: { userId: user._id, sessionId, refreshToken },
