     3→const ALGORITHM = 'aes-256-gcm';
     4→const IV_LENGTH = 16;
     5→const AUTH_TAG_LENGTH = 16;
     6→
     7→export const encrypt = ({
     8→	plaintext,
     9→	key,
    10→}: {
    11→	plaintext: string;
    12→	key: string;
    13→}): string => {
    14→	const iv = randomBytes(IV_LENGTH);
    15→	const cipher = createCipheriv(ALGORITHM, key, iv, { authTagLength: AUTH_TAG_LENGTH });
    16→	const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
    17→	const authTag = cipher.getAuthTag();
    18→	return Buffer.concat([iv, authTag, encrypted]).toString('base64url');
    19→};
    20→
    21→export const decrypt = ({
    22→	ciphertext,
    23→	key,
    24→}: {
    25→	ciphertext: string;
    26→	key: string;
    27→}): string => {
    28→	const data = Buffer.from(ciphertext, 'base64url');
    29→	const iv = data.subarray(0, IV_LENGTH);
    30→	const authTag = data.subarray(IV_LENGTH, IV_LENGTH + AUTH_TAG_LENGTH);
    31→	const encrypted = data.subarray(IV_LENGTH + AUTH_TAG_LENGTH);
    32→	const decipher = createDecipheriv(ALGORITHM, key, iv, {
    33→		authTagLength: AUTH_TAG_LENGTH,
    34→	});
    35→	decipher.setAuthTag(authTag);
    36→	return Buffer.concat([decipher.update(encrypted), decipher.final()]).toString('utf8');
    37→};
