     9→
    10→import { IS_PUBLIC_KEY } from '@modules/auth/decorators/public.decorator';
    11→import { IJwtPayload, IRequestUser } from '@modules/auth/types/auth.interface';
    12→import { SessionService } from '@modules/session/session.service';
    13→
    14→import type { FastifyRequest } from 'fastify';
    15→
    16→@Injectable()
    17→export class AuthGuard implements CanActivate {
    18→	constructor(
    19→		private readonly jwtService: JwtService,
    20→		private readonly sessionService: SessionService,
    21→		private readonly reflector: Reflector,
    22→	) {}
    23→
    24→	async canActivate(context: ExecutionContext): Promise<boolean> {
    25→		const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
    26→			context.getHandler(),
    27→			context.getClass(),
    28→		]);
    29→		if (isPublic) return true;
    30→
    31→		const request = context
    32→			.switchToHttp()
    33→			.getRequest<FastifyRequest & { user?: IRequestUser }>();
    34→		const token = this.extractTokenFromHeader(request);
    35→		if (!token) throw new UnauthorizedException();
    36→
    37→		let payload: IJwtPayload;
    38→		try {
    39→			payload = await this.jwtService.verifyAsync<IJwtPayload>(token);
    40→		} catch {
    41→			throw new UnauthorizedException();
    42→		}
    43→
    44→		const session = await this.sessionService.getSession({
    45→			userId: payload.user_id,
    46→			sessionId: payload.session_id,
    47→		});
    48→		if (!session) throw new UnauthorizedException();
    49→
    50→		request.user = {
    51→			user_id: payload.user_id,
    52→			session_id: payload.session_id,
    53→			role: session.role,
    54→			company_id: session.company_id,
    55→		} satisfies IRequestUser;
    56→
    57→		return true;
    58→	}
    59→
    60→	private extractTokenFromHeader({ headers }: FastifyRequest): string | null {
    61→		const [type, token] = headers.authorization?.split(' ') ?? [];
    62→		return type === 'Bearer' ? (token ?? null) : null;
    63→	}
    64→}
